import socket
import network
import ujson
import ubinascii
import hashlib
import os
from ucollections import deque

# WiFi credentials - should be stored securely
WIFI_SSID = "your_wifi_ssid"
WIFI_PASSWORD = "your_wifi_password"

# WebSocket security constants
WS_MAGIC_STRING = b"258EAFA5-E914-47DA-95CA-C5AB0DC85B11"
ALLOWED_ACTIONS = {"turn_on", "turn_off", "get_status"}

class SecureWebSocketServer:
    def __init__(self):
        self.clients = []
        self.client_buffer = deque(maxlen=100)
        self._setup_wifi()
        
    def _setup_wifi(self):
        wlan = network.WLAN(network.STA_IF)
        wlan.active(True)
        wlan.connect(WIFI_SSID, WIFI_PASSWORD)
        while not wlan.isconnected():
            pass
        print("WiFi connected:", wlan.ifconfig())
        
    def _generate_accept_key(self, key):
        """Generate WebSocket accept key"""
        return ubinascii.b2a_base64(
            hashlib.sha1(key + WS_MAGIC_STRING).digest()
        ).decode().strip()
        
    def _validate_action(self, action):
        """Validate action is in allowed list"""
        return action in ALLOWED_ACTIONS
        
    def _validate_json(self, data):
        """Safely parse and validate JSON"""
        try:
            parsed = ujson.loads(data)
            if not isinstance(parsed, dict):
                return None
            if "action" not in parsed:
                return None
            if not self._validate_action(parsed["action"]):
                return None
            return parsed
        except Exception:
            return None
            
    def _handle_client_message(self, client_socket, message):
        """Handle incoming WebSocket message"""
        try:
            data = self._validate_json(message)
            if not data:
                return
                
            action = data["action"]
            print(f"Received action: {action}")
            
            # Process action securely
            if action == "turn_on":
                # Implement your device control logic here
                response = {"status": "success", "action": "turn_on"}
            elif action == "turn_off":
                # Implement your device control logic here
                response = {"status": "success", "action": "turn_off"}
            elif action == "get_status":
                # Implement your device status logic here
                response = {"status": "success", "action": "get_status", "device_status": "active"}
                
            # Send response back to client
            response_json = ujson.dumps(response)
            self._send_websocket_message(client_socket, response_json)
            
        except Exception as e:
            print(f"Error handling message: {e}")
            
    def _send_websocket_message(self, client_socket, message):
        """Send WebSocket message to client"""
        try:
            # WebSocket frame format
            frame = bytearray()
            frame.append(0x81)  # FIN + TEXT frame
            length = len(message)
            if length <= 125:
                frame.append(length)
            elif length <= 65535:
                frame.append(126)
                frame.extend(length.to_bytes(2, 'big'))
            else:
                frame.append(127)
                frame.extend(length.to_bytes(8, 'big'))
            frame.extend(message.encode())
            client_socket.send(frame)
        except Exception as e:
            print(f"Error sending message: {e}")
            
    def _handle_websocket_handshake(self, client_socket, request):
        """Handle WebSocket handshake"""
        try:
            # Extract Sec-WebSocket-Key
            key_line = [line for line in request.split('\r\n') if line.startswith('Sec-WebSocket-Key')]
            if not key_line:
                return False
                
            key = key_line[0].split(':')[1].strip()
            accept_key = self._generate_accept_key(key)
            
            # Send handshake response
            response = (
                "HTTP/1.1 101 Switching Protocols\r\n"
                "Upgrade: websocket\r\n"
                "Connection: Upgrade\r\n"
                f"Sec-WebSocket-Accept: {accept_key}\r\n"
                "\r\n"
            )
            client_socket.send(response.encode())
            return True
        except Exception as e:
            print(f"Handshake error: {e}")
            return False
            
    def start_server(self, port=80):
        """Start WebSocket server"""
        server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        server_socket.bind(('', port))
        server_socket.listen(5)
        print(f"WebSocket server listening on port {port}")
        
        while True:
            try:
                client_socket, addr = server_socket.accept()
                print(f"Client connected from {addr}")
                
                # Read initial request
                request = client_socket.recv(1024).decode()
                if not request:
                    client_socket.close()
                    continue
                    
                # Handle WebSocket handshake
                if 'Upgrade: websocket' in request:
                    if self._handle_websocket_handshake(client_socket, request):
                        self.clients.append(client_socket)
                        print("WebSocket connection established")
                        
                        # Handle messages
                        while True:
                            try:
                                data = client_socket.recv(1024)
                                if not data:
                                    break
                                    
                                # Parse WebSocket frame
                                if len(data) > 2:
                                    message = data[2:].decode()
                                    self._handle_client_message(client_socket, message)
                                    
                            except Exception as e:
                                print(f"Client message error: {e}")
                                break
                    else:
                        client_socket.close()
                else:
                    client_socket.close()
                    
            except Exception as e:
                print(f"Server error: {e}")
                continue

